// Brave Search — Fixed for AI Tool compatibility
// 2-second delay to prevent 422 rate-limit errors
await new Promise(r => setTimeout(r, 2000));

let query;
try {
  // Use try-catch to prevent the "Read only property 'name'" crash
  query = $fromAI('query', 'The search query string', 'string');
} catch (e) {
  return "Error: Search query not provided by the AI Agent.";
}

if (!query) return "Error: Query was empty.";

const url = new URL('https://api.search.brave.com/res/v1/web/search');
url.searchParams.set('q', query);
url.searchParams.set('count', '5');

try {
  const response = await fetch(url.toString(), {
    headers: {
      'Accept': 'application/json',
      'X-Subscription-Token': 'BSAMROExT8AILLcDUBOKwUJ-Z-xDAz0'
    }
  });

  if (!response.ok) {
    return `Brave Search Error: API returned ${response.status} for query: "${query}"`;
  }

  const data = await response.json();
  const items = (data.web?.results || data.results || []);
  const formatted = items.slice(0, 5).map(r => ({
    title: r.title,
    url: r.url,
    description: r.description || r.extra_snippets?.[0] || ''
  }));

  // Return a stringified JSON for AI Agent compatibility
  return JSON.stringify({ query, results: formatted, count: formatted.length });

} catch (err) {
  return "Error: Failed to connect to Brave Search API.";
}

